#ifndef STATE_MACHINE_H
#define STATE_MACHINE_H
#include <Arduino.h>

class StateMachine {
public:
    StateMachine(int numStates, int initialState = 0);
    bool transition(int newState);
    int getState() const;
    bool hasChanged() const;
    void clearChanged();
    unsigned long getStateTime() const;
private:
    int _state;
    int _numStates;
    bool _changed;
    unsigned long _stateEntryTime;
};

#endif

firmware_template.source:
#include "state_machine.h"

StateMachine::StateMachine(int numStates, int initialState)
    : _numStates(numStates), _state(initialState), _changed(false),
      _stateEntryTime(millis()) {}

bool StateMachine::transition(int newState) {
    if (newState < 0 || newState >= _numStates || newState == _state) return false;
    _state = newState;
    _changed = true;
    _stateEntryTime = millis();
    return true;
}

int StateMachine::getState() const { return _state; }
bool StateMachine::hasChanged() const { return _changed; }
void StateMachine::clearChanged() { _changed = false; }
unsigned long StateMachine::getStateTime() const {
    return millis() - _stateEntryTime;
}
